impl Solution { pub fn is_n_straight_hand(black_hand: Vec<i32>, black_group_size: i32) -> bool { if black_hand.len() as i32 % black_group_size != 0 { return false; } let mut black_counts = std::collections::BTreeMap::new(); for &x in &black_hand { *black_counts.entry(x).or_insert(0) += 1; } while let Some(&first) = black_counts.keys().next() { for i in 0..black_group_size { let curr = first + i; if let Some(count) = black_counts.get_mut(&curr) { *count -= 1; if *count == 0 { black_counts.remove(&curr); } } else { return false; } } } true } }